// Buduje zapytanie do Claude (Anthropic) + przenosi dane kandydata
const b = $json.body || {};
const schema = {
  type: "object",
  properties: {
    match: { type: "integer" },
    summary: { type: "string" },
    strengths: { type: "array", items: { type: "string" } },
    risks: { type: "array", items: { type: "string" } },
    redFlags: { type: "array", items: { type: "string" } },
    recommendation: { type: "string", enum: ["Do rozmowy", "Do weryfikacji", "Słabe dopasowanie"] }
  },
  required: ["match", "summary", "strengths", "risks", "redFlags", "recommendation"],
  additionalProperties: false
};
const prompt = "CV KANDYDATA: " + (b.cvText || "") + "  ||  STANOWISKO: " + (b.jobTitle || "") + " — " + (b.jobDescription || "");
return [{ json: {
  candidate: { name: b.candidateName || "—", jobTitle: b.jobTitle || "—", consent: b.consent === true },
  anthropic: {
    model: "claude-opus-4-8",
    max_tokens: 1024,
    system: "Oceniasz dopasowanie kandydata do stanowiska na podstawie CV i opisu roli. Oceniasz wyłącznie kompetencje i doświadczenie zawodowe. Ignorujesz wiek, płeć, pochodzenie, zdjęcie i inne dane wrażliwe (RODO art. 22, AI Act). Twoja ocena to rekomendacja dla człowieka, nie decyzja.",
    messages: [{ role: "user", content: prompt }],
    output_config: { format: { type: "json_schema", schema: schema } }
  }
}}];

// Parsuje odpowiedź Claude i strukturyzuje wynik dla dashboardu/bazy
let raw = "";
try { raw = ($json.content && $json.content[0] && $json.content[0].text) || ""; } catch (e) { raw = ""; }
raw = String(raw).trim();
if (raw.indexOf("```") === 0) { raw = raw.split("```json").join("").split("```").join("").trim(); }
let data;
try { data = JSON.parse(raw); } catch (e) { data = { match: 0, summary: "Nie udało się odczytać odpowiedzi modelu", strengths: [], risks: [], redFlags: [], recommendation: "Do weryfikacji" }; }
const cand = $('Buduj zapytanie').item.json.candidate;
const match = Math.max(0, Math.min(100, Number(data.match) || 0));
const ocena = match >= 85 ? "Wysokie dopasowanie" : (match >= 70 ? "Do weryfikacji" : "Niskie dopasowanie");
return [{ json: {
  kandydat: cand.name,
  stanowisko: cand.jobTitle,
  dopasowanie: match,
  ocena: ocena,
  rekomendacja: data.recommendation || "Do weryfikacji",
  podsumowanie: data.summary || "",
  mocneStrony: data.strengths || [],
  ryzyka: data.risks || [],
  flagi: data.redFlags || [],
  zgodaRODO: cand.consent === true,
  decyzja: "oczekuje na decyzję człowieka",
  utworzono: new Date().toISOString()
}}];

